state = {"battery_soc": 0.5, "demand_kw": 4800, "price_per_kwh": 0.28}

def take_action(state, action):
    if action == "charge":
        new_soc = min(1.0, state["battery_soc"] + 0.1)
        cost = state["price_per_kwh"] * 0.1
    elif action == "discharge":
        new_soc = max(0.0, state["battery_soc"] - 0.1)
        cost = -state["price_per_kwh"] * 0.1
    else:
        new_soc, cost = state["battery_soc"], 0
    reward = -cost
    return {**state, "battery_soc": new_soc}, reward

next_state, reward = take_action(state, "discharge")
print(next_state, reward)
